    [Description("Search the web for information on a query. Returns a list of result snippets.")]
    public async Task<string> WebSearch(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            var response = await s_httpClient.SendAsync(request);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync();
            return ParseSearchResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note with a title and content for later reference.")]
    public string AddNote(
        [Description("Short title for this note")] string title,
        [Description("The note content — a key finding or insight")] string content)
    {
        noteService.Add(title, content);
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetNotes()
    {
        var notes = noteService.GetAll();
        if (notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var sb = new StringBuilder();
        for (int i = 0; i < notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {notes[i].Title} ---");
            sb.AppendLine(notes[i].Content);
            sb.AppendLine();
        }

        Console.WriteLine($"  📋 Retrieved {notes.Count} note(s)");
        return sb.ToString();
    }

    private static string ParseSearchResults(string html)
    {
        var results = new StringBuilder();
        int count = 0;

        // Extract result snippets from DuckDuckGo HTML response
        var snippetMarker = "result__snippet";
        int pos = 0;

        while (count < 8 && (pos = html.IndexOf(snippetMarker, pos, StringComparison.Ordinal)) >= 0)
        {
            // Find the start of the content after the tag closes
            var tagClose = html.IndexOf('>', pos);
            if (tagClose < 0) break;

            var endTag = html.IndexOf('<', tagClose + 1);
            if (endTag < 0) break;

            var snippet = WebUtility.HtmlDecode(
                html[(tagClose + 1)..endTag].Trim());

            if (!string.IsNullOrWhiteSpace(snippet))
            {
                count++;
                results.AppendLine($"{count}. {snippet}");
            }

            pos = endTag;
        }

        return count > 0
            ? results.ToString()
            : "No results found. Try a different search query.";
    }
}

