    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable or AI:ApiKey in configuration.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(pipeline => pipeline
    .UseFunctionInvocation()
    .UseOpenAIChatClient(modelId, apiKey));

builder.Services.AddSingleton<NoteService>();
builder.Services.AddSingleton<ResearchTools>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var researchTools = host.Services.GetRequiredService<ResearchTools>();

IList<AITool> tools = AIFunctionFactory.Create(researchTools).Cast<AITool>().ToList();

var agent = new ChatClientAgent(
    chatClient,
    instructions: "You are a research assistant. Given a topic, use the WebSearch tool to find "
        + "relevant information from multiple angles. Use the AddNote tool to record key "
        + "findings as you go. After gathering enough information (at least 3 searches), "
        + "use GetNotes to review what you've collected, then provide a comprehensive "
        + "summary with the key findings organized by theme.",
    name: "ResearchAgent",
    tools: tools);

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var options = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(
    $"Research the following topic and summarize your findings: {topic}",
    options: options);

Console.WriteLine(response.Text);
Console.WriteLine();

